  type: 'singleSelect',
  name: 'string',
  unique: true,
  notNull: true,
  dbFieldName: 'string',
  isLookup: true,
  isConditionalLookup: true,
  description: 'this is a summary',
  lookupOptions: {
    foreignTableId: 'string',
    lookupFieldId: 'string',
    linkFieldId: 'string',
    filter: {}
  },
  options: {
    expression: 'countall({values})',
    timeZone: 'string',
    formatting: null,
    showAs: {type: 'url'}
  },
  aiConfig: {
    modelKey: 'string',
    isAutoFill: true,
    attachPrompt: 'string',
    type: 'extraction',
    sourceFieldId: 'string'
  },
  id: 'fldxxxxxxxxxxxxxxxx',
  order: {viewId: 'string', orderIndex: 0}
}));
req.end();

